"""Money helpers. All monetary amounts are integer CENTS to avoid float drift."""


def to_cents(dollars):
    """Convert a dollar float/str to integer cents, rounding to nearest cent."""
    # Use round-half-up on the dollar value scaled to cents.
    # We add a tiny epsilon-free approach via Decimal-like manual rounding.
    scaled = float(dollars) * 100.0
    # Round half up.
    if scaled >= 0:
        return int(scaled + 0.5)
    return -int(-scaled + 0.5)


def cents_to_str(cents):
    """Format integer cents as a dollar string like '12.34' (no currency symbol).

    TODO(money): support a currency symbol / locale-aware formatting param.
    """
    sign = "-" if cents < 0 else ""
    cents = abs(int(cents))
    return "{}{}.{:02d}".format(sign, cents // 100, cents % 100)

"""Aggregate line items into per-customer subtotals.

A line item is a dict:
    {"customer": str, "kind": "full"|"prorated", "plan_cents": int, "days": int}

For "full" items the charge is plan_cents. For "prorated" items the charge is
proration.prorate(plan_cents, days).
"""

from billing.proration import prorate


def charge_for_item(item):
    if item["kind"] == "full":
        return int(item["plan_cents"])
    elif item["kind"] == "prorated":
        return prorate(item["plan_cents"], item["days"])
    raise ValueError("unknown item kind: {}".format(item["kind"]))


def subtotals_by_customer(items):
    """Return an ordered dict-like {customer: subtotal_cents} preserving first-seen order."""
    out = {}
    order = []
    for item in items:
        c = item["customer"]
        if c not in out:
            out[c] = 0
            order.append(c)
        out[c] += charge_for_item(item)
    return {c: out[c] for c in order}

"""Group events into per-local-day buckets.

Public API:
    counts_by_day(events, zone) -> {day_key: count}   (insertion order = first seen)
    latency_by_day(events, zone) -> {day_key: [latency_ms, ...]}
"""

from events import local_day_key


def counts_by_day(events, zone):
    out = {}
    for e in events:
        key = local_day_key(e["ts"], zone)
        out[key] = out.get(key, 0) + 1
    return out


def latency_by_day(events, zone):
    out = {}
    for e in events:
        key = local_day_key(e["ts"], zone)
        out.setdefault(key, []).append(e["latency_ms"])
    return out

