"""Hidden integration test for the daily analytics report.

Run: python3 test_hidden.py
Exits nonzero on any failure.
"""
import unittest

from report import build_report
from events import local_day_key, parse_epoch
from analytics.buckets import counts_by_day


def ev(ts, latency_ms=100, user="u"):
    return {"ts": ts, "user": user, "latency_ms": latency_ms}


class TestIntegrationTimezone(unittest.TestCase):
    """FAIL_TO_PASS: zone must be honored end to end."""

    def test_busiest_day_uses_local_time_pacific(self):
        events = []
        for h in ("03:00:00", "03:30:00", "04:00:00", "04:30:00", "05:00:00"):
            events.append(ev("2026-03-15T" + h + "Z", latency_ms=100))
        for h in ("20:00:00", "21:00:00", "22:00:00"):
            events.append(ev("2026-03-15T" + h + "Z", latency_ms=200))

        r = build_report(events, "US/Pacific")
        self.assertEqual(r["daily_counts"].get("2026-03-14"), 5)
        self.assertEqual(r["daily_counts"].get("2026-03-15"), 3)
        self.assertEqual(r["busiest_day"], "2026-03-14")
        self.assertEqual(r["total_events"], 8)
        self.assertAlmostEqual(r["avg_latency_ms"]["2026-03-14"], 100.0)
        self.assertAlmostEqual(r["avg_latency_ms"]["2026-03-15"], 200.0)

    def test_local_day_key_negative_offset(self):
        self.assertEqual(local_day_key("2026-03-15T03:30:00Z", "US/Pacific"), "2026-03-14")

    def test_local_day_key_fractional_positive_offset(self):
        self.assertEqual(local_day_key("2026-03-14T20:00:00Z", "Asia/Kolkata"), "2026-03-15")

    def test_local_day_key_chatham_quarter_hour(self):
        self.assertEqual(local_day_key("2026-03-14T12:00:00Z", "Pacific/Chatham"), "2026-03-15")

    def test_counts_split_across_boundary_kolkata(self):
        events = [
            ev("2026-03-14T18:00:00Z"),
            ev("2026-03-14T19:00:00Z"),
            ev("2026-03-14T20:00:00Z"),
        ]
        counts = counts_by_day(events, "Asia/Kolkata")
        self.assertEqual(counts.get("2026-03-14"), 1)
        self.assertEqual(counts.get("2026-03-15"), 2)


class TestRegression(unittest.TestCase):
    """PASS_TO_PASS."""

    def test_utc_zone_unchanged(self):
        self.assertEqual(local_day_key("2026-03-15T03:30:00Z", "UTC"), "2026-03-15")

    def test_parse_epoch(self):
        self.assertEqual(parse_epoch("2026-03-15T00:00:00Z"), 1773532800)

    def test_parse_epoch_requires_z(self):
        with self.assertRaises(ValueError):
            parse_epoch("2026-03-15T00:00:00")

    def test_unknown_zone_raises(self):
        with self.assertRaises(KeyError):
            local_day_key("2026-03-15T00:00:00Z", "Mars/Olympus")

    def test_total_and_shape(self):
        r = build_report([ev("2026-03-15T12:00:00Z")], "UTC")
        self.assertEqual(set(r.keys()), {"daily_counts", "busiest_day", "total_events", "avg_latency_ms"})
        self.assertEqual(r["total_events"], 1)
        self.assertEqual(r["busiest_day"], "2026-03-15")

    def test_tie_break_earliest_day(self):
        events = [
            ev("2026-03-16T12:00:00Z"),
            ev("2026-03-15T12:00:00Z"),
        ]
        r = build_report(events, "UTC")
        self.assertEqual(r["busiest_day"], "2026-03-15")


if __name__ == "__main__":
    unittest.main(verbosity=2)

