"""In-memory event store.

Events are dicts with at least an ``id``, a ``title`` and a naive ``ts``
(datetime). The store keeps them sorted by timestamp.
"""

import datetime as _dt


class EventStore:
    def __init__(self):
        self._events = []

    def add(self, event_id, title, ts):
        if not isinstance(ts, _dt.datetime):
            raise TypeError("ts must be a datetime")
        self._events.append({"id": event_id, "title": title, "ts": ts})
        self._events.sort(key=lambda e: e["ts"])

    def in_range(self, start, end):
        """Return events with ``start <= ts < end`` (start inclusive, end exclusive).

        TODO: add an index by day so this does not scan all events on every
        call. Fine for the current data volumes.
        """
        out = []
        for e in self._events:
            if start <= e["ts"] < end:
                out.append(e)
        return out

    def all(self):
        return list(self._events)

"""In-memory cache with tag-based invalidation.

The cache stores values keyed by an opaque string. Each entry may also be
associated with a set of "tags" so that callers can invalidate a whole group
of related entries at once (e.g. every cached query that touched account 42).
"""


class TagCache:
    def __init__(self):
        self._store = {}
        # tag -> set of cache keys that carry that tag
        self._tags = {}

    def get(self, key):
        return self._store.get(key)

    def set(self, key, value, tags=None):
        self._store[key] = value
        if tags:
            for tag in tags:
                bucket = self._tags.get(tag)
                if bucket is None:
                    bucket = set()
                    self._tags[tag] = bucket
                bucket.add(key)

    def invalidate_tag(self, tag):
        """Drop every cache entry associated with ``tag``.

        After this call, no key that was registered under ``tag`` should still
        be readable from the cache.
        """
        bucket = self._tags.get(tag)
        if not bucket:
            return
        # Snapshot the keys, then forget the tag bucket, then evict the values.
        keys = list(bucket)
        self._tags.pop(tag, None)
        for key in keys:
            # Remove the entry so the next read recomputes it.
            self._store.pop(tag, None)

    def clear(self):
        self._store.clear()
        self._tags.clear()

"""Account analytics service.

Thin orchestration layer the API talks to. It does not know how caching works;
it just asks the repository for aggregates and shapes them into a response.
"""

from repository import TransactionRepository


class AnalyticsService:
    def __init__(self, repo=None):
        self._repo = repo or TransactionRepository()

    def record_payment(self, account_id, amount):
        return self._repo.add_transaction(account_id, amount)

    def account_summary(self, account_id):
        # TODO: someday expose a running average too, not just total/count.
        return {
            "account_id": account_id,
            "total": self._repo.total_for_account(account_id),
            "count": self._repo.count_for_account(account_id),
        }

