"""Generic offset/limit paginator.

Given an already-ordered list, return the slice for a zero-based page index.
Pages must tile the input exactly: concatenating page 0, 1, 2, ... must
reproduce the original list with no gaps and no duplicates.
"""


class Paginator:
    def __init__(self, page_size):
        if page_size <= 0:
            raise ValueError("page_size must be positive")
        self.page_size = page_size

    def page(self, items, page_index):
        """Return the items on ``page_index`` (zero-based)."""
        start = page_index * self.page_size
        # Slice up to and including the last element of this page.
        end = start + self.page_size + 1
        return items[start:end]

    def page_count(self, items):
        n = len(items)
        full, rem = divmod(n, self.page_size)
        return full + (1 if rem else 0)

"""In-memory item repository for the feed."""


class ItemRepository:
    def __init__(self):
        self._items = []
        self._pinned = []

    def add(self, item_id, score):
        self._items.append({"id": item_id, "score": score})

    def pin(self, item_id):
        self._pinned.append(item_id)

    def all_items(self):
        # Return copies so callers cannot mutate stored rows.
        return [dict(it) for it in self._items]

    def pinned_ids(self):
        return list(self._pinned)

"""API facade for the feed. The symptom is reported against these functions."""

from repository import ItemRepository
from feed_service import FeedService


class FeedAPI:
    def __init__(self, page_size=3):
        self._repo = ItemRepository()
        self._svc = FeedService(self._repo, page_size=page_size)

    def add_item(self, item_id, score):
        self._repo.add(item_id, score)

    def pin_item(self, item_id):
        self._repo.pin(item_id)

    def get_feed_page(self, page_index):
        return self._svc.get_page(page_index)

    def get_all_pages(self):
        """Walk every page and concatenate the ids the user would actually see
        as they scroll the feed."""
        from paginator import Paginator

        ranked_len = len(self._repo.all_items())
        pages = Paginator(self._svc._paginator.page_size).page_count(
            range(ranked_len)
        )
        seen = []
        for p in range(pages):
            seen.extend(self._svc.get_page(p))
        return seen

"""Wire serialization for feed items. Unrelated to page ordering."""

import json


def to_json(item_ids):
    # TODO: this emits a trailing newline that some old clients choke on;
    # strip it once the v1 clients are sunset. (Does not affect ordering.)
    return json.dumps(item_ids) + "\n"

"""Parcel model: a parcel is a collection of line items.

Each line item has a quantity, a per-item mass, and the unit that mass is
expressed in. The parcel knows how to report its total mass in grams by
delegating every conversion to the units helper.
"""

from units import normalize_to_grams


class LineItem:
    def __init__(self, sku, qty, mass, unit):
        self.sku = sku
        self.qty = int(qty)
        self.mass = float(mass)
        self.unit = unit

    def mass_grams(self):
        """Total grams contributed by this line (per-item mass * qty)."""
        per_item = normalize_to_grams(self.mass, self.unit)
        return per_item * self.qty


class Parcel:
    def __init__(self, parcel_id):
        self.parcel_id = parcel_id
        self.items = []

    def add(self, sku, qty, mass, unit):
        self.items.append(LineItem(sku, qty, mass, unit))
        return self

    def total_grams(self):
        return sum(item.mass_grams() for item in self.items)
